import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.DhtYoOpx.js";const c=JSON.parse('{"title":"React 常见面试题（二）","description":"","frontmatter":{"title":"React 常见面试题（二）","date":"2024-01-01T00:00:00.000Z"},"headers":[],"relativePath":"articles/vue/react/react-interview-2.md","filePath":"articles/vue/react/react-interview-2.md","lastUpdated":1776146674000}'),n={name:"articles/vue/react/react-interview-2.md"};function l(p,s,r,h,o,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<p><strong>百度前端二面</strong></p><p>1.先问了问项目，又问了下相关的react-three-fiber</p><p>2.ssr和csr的区别</p><p>3.增量渲染（？）</p><p>4.项目里怎么做的响应式布局</p><p>5.px转rem有没有什么好的方法（vscode里直接转的，不知道）</p><p>6.grid布局和flex布局用法，有什么本质上的区别</p><p>7.grid布局怎么设置间距</p><ul><li>grid-row-gap：行距；</li><li>grid-column-gap：列距；</li></ul><p>8.前端性能优化，问一些很具体的指标</p><ul><li>FP，FCP，FMP，ATF，TTI</li></ul><p>9.前端图片优化的几种方式</p><p>10.写一个react组件</p><p>11.在组件里发ajax请求</p><p><strong>京东前端一面（11.11）</strong></p><p>1.React函数组件和类式组件的区别 2.React函数式组件的生命周期 3.state的更新是异步的，如何保证获取的state是最新的值 4.js事件执行机制；宏任务，微任务有哪些 5.基本数据类型有哪些，判断类型的方式 6.Object.prototype.tostring.call()返回的数据结构 7.数组的方法，哪些会操作原数组，哪些不能对原数组进行操作 8.http状态码 301，302，304 9.强缓存与协商缓存</p><p>10.场景题 ：要书写一个商品详情页（研发排期是多少，应该怎么去构思）</p><p>11.css：左侧固定宽度，右侧随浏览器的宽度大小而改变（怎么实现，有哪些方法，如果使用flex实现应该设置哪些属性）</p><p>12.响应式布局（vh，vw）</p><h2 id="react-如何区分-class组件-和-function组件" tabindex="-1">React 如何区分 Class组件 和 Function组件 <a class="header-anchor" href="#react-如何区分-class组件-和-function组件" aria-label="Permalink to &quot;React 如何区分 Class组件 和 Function组件&quot;">​</a></h2><p>一般的方式是借助 typeof 和 Function.prototype.toString 来判断当前是不是 class，如下：</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> isClass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">func</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> func </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;function&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    &amp;&amp;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">^</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">class</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">prototype</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.toString.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">call</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(func));</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>但是这个方式有它的局限性，因为如果用了 babel 等转换工具，将 class 写法全部转为 function 写法，上面的判断就会失效。</p><p>React 区分 Class组件 和 Function组件的方式很巧妙，由于所有的类组件都要继承 React.Component，所以只要判断原型链上是否有 React.Component 就可以了：</p><div class="language-jsx vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">AComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">prototype</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> instanceof</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> React</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Component</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="redux异步中间件之间的优劣" tabindex="-1">redux异步中间件之间的优劣? <a class="header-anchor" href="#redux异步中间件之间的优劣" aria-label="Permalink to &quot;redux异步中间件之间的优劣?&quot;">​</a></h2><p><strong>redux-thunk优点:</strong></p><ul><li>体积小: redux-thunk的实现方式很简单,只有不到20行代码</li><li>使用简单: redux-thunk没有引入像redux-saga或者redux-observable额外的范式,上手简单</li></ul><p><strong>redux-thunk缺陷:</strong></p><ul><li>样板代码过多: 与redux本身一样,通常一个请求需要大量的代码,而且很多都是重复性质的</li><li>耦合严重: 异步操作与redux的action偶合在一起,不方便管理</li><li>功能孱弱: 有一些实际开发中常用的功能需要自己进行封装</li></ul><p><strong>redux-saga优点:</strong></p><ul><li>异步解耦: 异步操作被被转移到单独 saga.js 中，不再是掺杂在 action.js 或 component.js 中</li><li>action摆脱thunk function: dispatch 的参数依然是一个纯粹的 action (FSA)，而不是充满 &quot;黑魔法&quot; thunk function</li><li>异常处理: 受益于 generator function 的 saga 实现，代码异常/请求失败 都可以直接通过 try/catch 语法直接捕获处理</li><li>功能强大: redux-saga提供了大量的Saga 辅助函数和Effect 创建器供开发者使用,开发者无须封装或者简单封装即可使用</li><li>灵活: redux-saga可以将多个Saga可以串行/并行组合起来,形成一个非常实用的异步flow</li><li>易测试，提供了各种case的测试方案，包括mock task，分支覆盖等等</li></ul><p><strong>redux-saga缺陷:</strong></p><ul><li>额外的学习成本: redux-saga不仅在使用难以理解的 generator function,而且有数十个API,学习成本远超redux-thunk,最重要的是你的额外学习成本是只服务于这个库的,与redux-observable不同,redux-observable虽然也有额外学习成本但是背后是rxjs和一整套思想</li><li>体积庞大: 体积略大,代码近2000行，min版25KB左右</li><li>功能过剩: 实际上并发控制等功能很难用到,但是我们依然需要引入这些代码</li><li>ts支持不友好: yield无法返回TS类型</li></ul><p><strong>redux-observable优点:</strong></p><ul><li>功能最强: 由于背靠rxjs这个强大的响应式编程的库,借助rxjs的操作符,你可以几乎做任何你能想到的异步处理</li><li>背靠rxjs: 由于有rxjs的加持,如果你已经学习了rxjs,redux-observable的学习成本并不高,而且随着rxjs的升级redux-observable也会变得更强大</li></ul><p><strong>redux-observable缺陷:</strong></p><ul><li>学习成本奇高: 如果你不会rxjs,则需要额外学习两个复杂的库</li><li>社区一般: redux-observable的下载量只有redux-saga的1/5,社区也不够活跃,在复杂异步流中间件这个层面redux-saga仍处于领导地位</li></ul><p>详见：<a href="https://hackmd.io/@2qVnJRlJRHCk20dvVxsySA/H1xLHUQ8e?type=view#side-by-side-**comparison**" target="_blank" rel="noreferrer">https://hackmd.io/@2qVnJRlJRHCk20dvVxsySA/H1xLHUQ8e?type=view#side-by-side-<strong>comparison</strong></a></p>`,39)])])}const u=i(n,[["render",l]]);export{c as __pageData,u as default};
